import{Logger}from '../shared/logger.js';class FileUpload{constructor(container,options={}){this.container=typeof container==='string' ? document.querySelector(container): container;if(!this.container)return;this.options={maxFiles: 10,maxSize: 10*1024*1024,acceptedTypes: null,uploadUrl: this.container.dataset.uploadUrl||'/api/upload',...options};this.files=[];this.init();}init(){this.createUI();this.bindEvents();}createUI(){this.container.innerHTML=`<div class="file-upload-area" tabindex="0"><div class="file-upload-icon"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M17 8l-5-5-5 5M12 3v12"/></svg></div><p class="file-upload-text">Drag&drop files here</p><p class="file-upload-hint">or<span class="file-upload-browse">browse</span>to select</p><input type="file" class="file-upload-input" ${this.options.maxFiles>1 ? 'multiple' : ''}${this.options.acceptedTypes ? `accept="${this.options.acceptedTypes.join(',')}"` : ''}></div><div class="file-upload-progress" style="display: none;"><div class="progress-bar"></div><span class="progress-text">0%</span></div><div class="file-upload-list"></div>`;this.uploadArea=this.container.querySelector('.file-upload-area');this.fileInput=this.container.querySelector('.file-upload-input');this.progressArea=this.container.querySelector('.file-upload-progress');this.progressBar=this.container.querySelector('.progress-bar');this.progressText=this.container.querySelector('.progress-text');this.fileList=this.container.querySelector('.file-upload-list');}bindEvents(){this.uploadArea.addEventListener('dragover',(e)=>this.onDragOver(e));this.uploadArea.addEventListener('dragleave',(e)=>this.onDragLeave(e));this.uploadArea.addEventListener('drop',(e)=>this.onDrop(e));this.uploadArea.addEventListener('click',()=>this.fileInput.click());this.uploadArea.addEventListener('keydown',(e)=>{if(e.key==='Enter'||e.key===' '){this.fileInput.click();}});this.fileInput.addEventListener('change',(e)=>this.onFilesSelected(e.target.files));}onDragOver(e){e.preventDefault();this.uploadArea.classList.add('dragover');}onDragLeave(e){e.preventDefault();this.uploadArea.classList.remove('dragover');}onDrop(e){e.preventDefault();this.uploadArea.classList.remove('dragover');this.onFilesSelected(e.dataTransfer.files);}onFilesSelected(files){const newFiles=Array.from(files).filter(file=>this.validateFile(file));if(newFiles.length+this.files.length>this.options.maxFiles){this.showError(`Maximum ${this.options.maxFiles}files allowed`);return;}this.files.push(...newFiles);this.renderFiles();this.uploadFiles(newFiles);}validateFile(file){if(file.size>this.options.maxSize){this.showError(`${file.name}exceeds ${this.formatSize(this.options.maxSize)}`);return false;}if(this.options.acceptedTypes){const matches=this.options.acceptedTypes.some(type=>{if(type.includes('*')){return file.type.startsWith(type.replace('*',''));}return file.type===type||file.name.endsWith(type);});if(!matches){this.showError(`${file.name}is not an accepted file type`);return false;}}return true;}async uploadFiles(files){this.progressArea.style.display='block';for(let i=0;i<files.length;i++){await this.uploadFile(files[i],i,files.length);}this.progressArea.style.display='none';}async uploadFile(file,index,total){const formData=new FormData();formData.append('file',file);return new Promise((resolve,reject)=>{const xhr=new XMLHttpRequest();xhr.upload.addEventListener('progress',(e)=>{if(e.lengthComputable){const percent=(e.loaded/e.total)*100;this.progressBar.style.width=`${percent}%`;this.progressText.textContent=`${Math.round(percent)}%`;}});xhr.addEventListener('load',()=>{if(xhr.status===200){this.updateFileStatus(file.name,'success');resolve(JSON.parse(xhr.responseText));}else{this.updateFileStatus(file.name,'error');reject(new Error('Upload failed'));}});xhr.addEventListener('error',()=>{this.updateFileStatus(file.name,'error');reject(new Error('Upload failed'));});xhr.open('POST',this.options.uploadUrl);xhr.send(formData);});}renderFiles(){this.fileList.innerHTML=this.files.map((file,index)=>`<div class="file-upload-item" data-index="${index}"><div class="file-upload-item-info"><span class="file-upload-item-icon">${this.getFileIcon(file.type)}</span><span class="file-upload-item-name">${file.name}</span><span class="file-upload-item-size">${this.formatSize(file.size)}</span></div><div class="file-upload-item-status"><span class="status-indicator"></span><button class="file-upload-item-remove" onclick="window.fileUpload_${this.container.id||'default'}.removeFile(${index})"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button></div></div>`).join('');}updateFileStatus(fileName,status){const item=Array.from(this.fileList.children).find(el=>el.querySelector('.file-upload-item-name')?.textContent===fileName);if(item){item.classList.remove('uploading','success','error');item.classList.add(status);}}removeFile(index){this.files.splice(index,1);this.renderFiles();}getFileIcon(type){if(type.startsWith('image/'))return '🖼️';if(type.startsWith('video/'))return '🎬';if(type.startsWith('audio/'))return '🎵';if(type.includes('pdf'))return '📄';if(type.includes('word')||type.includes('document'))return '📝';if(type.includes('excel')||type.includes('spreadsheet'))return '📊';return '📁';}formatSize(bytes){if(bytes<1024)return `${bytes}B`;if(bytes<1024*1024)return `${(bytes/1024).toFixed(1)}KB`;return `${(bytes/1024/1024).toFixed(1)}MB`;}showError(message){Logger.error(message);}getFiles(){return this.files;}clear(){this.files=[];this.renderFiles();}}if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('.file-upload,[data-file-upload]').forEach(container=>{const id=container.id||`file-upload-${Math.random().toString(36).slice(2)}`;container.id=id;window[`fileUpload_${id}`]=new FileUpload(container);});});}export default FileUpload;